<?php
namespace App\Modules\Hr\Recruitment\Actions; use App\Modules\Hr\Core\Services\HrAuditService;use App\Modules\Hr\Core\Services\TenantContext;use App\Modules\Hr\Recruitment\Models\HrJobPosting;
class CreateJobPostingAction{public function __construct(private HrAuditService $audit){}public function execute(array $data):HrJobPosting{abort_unless(auth()->user()?->hasHrPermission('hr.recruitment.create_posting'),403);$tenant=app(TenantContext::class)->getId();$code=strtoupper(trim((string)($data['code']??'')));abort_if($code===''||blank($data['title']??null)||(int)($data['headcount']??0)<1,422);abort_if(HrJobPosting::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->where('code',$code)->exists(),422);$row=HrJobPosting::create(['legal_entity_id'=>$tenant,'code'=>$code,'title'=>trim($data['title']),'headcount'=>(int)$data['headcount'],'description'=>$data['description']??null,'requirements'=>$data['requirements']??null,'status'=>'draft','closes_on'=>$data['closes_on']??null,'created_by'=>auth()->id()]);$this->audit->log('recruitment_posting_created',$row);return $row;}public function publish(HrJobPosting $posting):HrJobPosting{abort_unless(auth()->user()?->hasHrPermission('hr.recruitment.create_posting'),403);abort_unless($posting->legal_entity_id===app(TenantContext::class)->getId()&&$posting->status==='draft',422);$posting->update(['status'=>'published','published_on'=>today()]);$this->audit->log('recruitment_posting_published',$posting);return $posting->fresh();}}
